class Solution:
    def distinctAverages(self, nums):
        a = list(nums)
        seen = set()
        while a:
            mn = min(a)
            a.remove(mn)
            mx = max(a)
            a.remove(mx)
            seen.add((mn + mx) / 2)
        return len(seen)

