var distinctAverages = function(nums) {
    const a = nums.slice().sort((x, y) => x - y);
    let i = 0, j = a.length - 1;
    const seen = new Set();
    while (i < j) {
        seen.add(a[i] + a[j]);
        i++; j--;
    }
    return seen.size;
};
